#include <iostream>
#include <string>

enum class Light
{
    red,
    yellow,
    green
};

std::string lightToString(Light l)
{
    switch (l)
    {
        case Light::red:    return "Red";
        case Light::yellow: return "Yellow";
        case Light::green:  return "Green";
        default:            return "Unknown";
    }
}

std::string lightToAction(Light l)
{
    switch (l)
    {
        case Light::red:    return "Stop";
        case Light::yellow: return "Caution";
        case Light::green:  return "Go";
        default:            return "Invalid";
    }
}

int main()
{
    int code{};
    std::cin >> code;

    Light light{ static_cast<Light>(code) };
    std::cout << lightToString(light) << ": " << lightToAction(light) << '\n';

    return 0;
}

