#include <iostream>
#include <string>

enum class Permission : int
{
    read    = 1,
    write   = 2,
    execute = 4
};

bool hasPermission(int mask, Permission p)
{
    return (mask & static_cast<int>(p)) != 0;
}

int main()
{
    int mask{};
    std::cin >> mask;

    std::cout << "Read: "    << (hasPermission(mask, Permission::read)    ? "yes" : "no") << '\n';
    std::cout << "Write: "   << (hasPermission(mask, Permission::write)   ? "yes" : "no") << '\n';
    std::cout << "Execute: " << (hasPermission(mask, Permission::execute) ? "yes" : "no") << '\n';

    return 0;
}
